def solve(n,b):
    # write code here
    # return the answer
    b.sort()
    a=[0]*(2*n)
    for i in range(n):
        a[2*i]=b[i]
    for i in range(n):
        a[2*i+1]=b[n-i-1]
    for i in range(2*n-1):
        if a[i]>a[i+1]:
            return -1
    return a

t=int(input())
for i in range(t):
    n=int(input())
    b=list(map(int,input().split()))
    print(*solve(n,b))
